    "key": "settings__point-storage",
    "group": "settings",
    "label": "Settings > Point Storage",
    "chart": "stateDiagram-v2\n    [*] --> TopLevelGrid\n\n    TopLevelGrid --> PointStorageMenu : OPEN_POINTSTORAGE_MENU\\n[pointStorageMenuVisible]\n    TopLevelGrid --> TopLevelGrid : LEICA_KEY\\n(shell exits to Home)\n\n    PointStorageMenu --> TopLevelGrid : BACK\n    PointStorageMenu --> DuplicatePoints       : SELECT(duplicatePoints)\\n[canShowDuplicatePoints]\n    PointStorageMenu --> PromptBeforeStoring   : SELECT(promptBeforeStoring)\\n[canShowPromptBeforeStoring]\n    PointStorageMenu --> GnssQualityControl    : SELECT(gnssQualityControl)\\n[canShowGnssQualityControl]\n    PointStorageMenu --> TpsQualityControl     : SELECT(tpsQualityControl)\\n[canShowTpsQualityControl]\n    PointStorageMenu --> ImagingQualityControl : SELECT(imagingQualityControl)\\n[canShowImagingQualityControl]\n    PointStorageMenu --> AutopoleOffsetsChecks : SELECT(autopoleOffsetsChecks)\\n[canShowAutopoleOffsetsChecks]\n\n    %% ── Duplicate Points ────────────────────────────────────────────────────\n    %% Mode-driven field visibility (UpdateCtrls).\n    %% F1/CONT: SaveChanges + SyncAverageSettingToMeasJob + Close.\n    state DuplicatePoints {\n        [*] --> DP_NormalAveraging\n        DP_NormalAveraging    : NormalAveraging\\n(Method + LimitPos + LimitHeight visible)\n        DP_ShowWarning        : ShowWarning\\n(all limit fields hidden)\n        DP_AbsoluteDifference : AbsoluteDifference\\n(Easting/Northing/Height/CartesianXYZ visible)\n        DP_AveragingOff       : AveragingOff\\n(all limit fields hidden)\n\n        DP_NormalAveraging    --> DP_ShowWarning        : AVG_MODE_CHANGED(ShowWarning)\n        DP_NormalAveraging    --> DP_AbsoluteDifference : AVG_MODE_CHANGED(AbsoluteDifference)\n        DP_NormalAveraging    --> DP_AveragingOff       : AVG_MODE_CHANGED(AveragingOff)\n        DP_ShowWarning        --> DP_NormalAveraging    : AVG_MODE_CHANGED(NormalAveraging)\n        DP_ShowWarning        --> DP_AbsoluteDifference : AVG_MODE_CHANGED(AbsoluteDifference)\n        DP_ShowWarning        --> DP_AveragingOff       : AVG_MODE_CHANGED(AveragingOff)\n        DP_AbsoluteDifference --> DP_NormalAveraging    : AVG_MODE_CHANGED(NormalAveraging)\n        DP_AbsoluteDifference --> DP_ShowWarning        : AVG_MODE_CHANGED(ShowWarning)\n        DP_AbsoluteDifference --> DP_AveragingOff       : AVG_MODE_CHANGED(AveragingOff)\n        DP_AveragingOff       --> DP_NormalAveraging    : AVG_MODE_CHANGED(NormalAveraging)\n        DP_AveragingOff       --> DP_ShowWarning        : AVG_MODE_CHANGED(ShowWarning)\n        DP_AveragingOff       --> DP_AbsoluteDifference : AVG_MODE_CHANGED(AbsoluteDifference)\n    }\n    DuplicatePoints --> PointStorageMenu : SETTINGS_CLOSED / BACK\n\n    %% ── Prompt Before Storing ───────────────────────────────────────────────\n    %% Tabbed: TPS tab (IsMeasSystemAvailable MS_TPS), GNSS tab (MS_GNSS).\n    %% Single tab hides tab bar. GNSS auto-selected when IsMeasSystemActive(MS_GNSS).\n    %% F1/CONT: SaveChanges + Close.\n    state PromptBeforeStoring {\n        [*] --> PBS_SelectingTab\n        PBS_SelectingTab : SelectingTab\\n(auto-select GNSS if active)\n        PBS_TpsTab       : TpsTab\\n(eTpsPrompt checkbox)\n        PBS_GnssTab      : GnssTab\\n(eGpsPrompt checkbox)\n\n        PBS_SelectingTab --> PBS_TpsTab  : tab selected (MS_TPS available)\n        PBS_SelectingTab --> PBS_GnssTab : tab selected (MS_GNSS available\\nor IsMeasSystemActive)\n        PBS_TpsTab       --> PBS_GnssTab : tab changed\n        PBS_GnssTab      --> PBS_TpsTab  : tab changed\n    }\n    PromptBeforeStoring --> PointStorageMenu : SETTINGS_CLOSED / BACK\n\n    %% ── GNSS Quality Control ────────────────────────────────────────────────\n    %% AutoStop toggle → StopCriterion dropdown visibility + F3 PARAM key.\n    %% CheckQuality toggle → Check/MaxAllowed field visibility.\n    %% F1/CONT: SaveChanges + Close. F3/PARAM: opens stop-criteria sub-controller.\n    state GnssQualityControl {\n        [*] --> GQC_AutoStopOff\n        GQC_AutoStopOff : AutoStopOff\\n(StopCriterion hidden, F3 hidden)\n\n        state GQC_AutoStopOn {\n            [*] --> GQC_CheckQualityOff\n            GQC_CheckQualityOff : CheckQualityOff\\n(Check + MaxAllowed hidden)\n            GQC_CheckQualityOn  : CheckQualityOn\\n(Check visible;\\nMaxAllowed shown if Check≠None)\n            GQC_CheckQualityOff --> GQC_CheckQualityOn  : CHECK_QUALITY_CHANGED(true)\n            GQC_CheckQualityOn  --> GQC_CheckQualityOff : CHECK_QUALITY_CHANGED(false)\n        }\n\n        GQC_AutoStopOff --> GQC_AutoStopOn  : AUTO_STOP_CHANGED(true)\n        GQC_AutoStopOn  --> GQC_AutoStopOff : AUTO_STOP_CHANGED(false)\n    }\n    GnssQualityControl --> PointStorageMenu : SETTINGS_CLOSED / BACK\n\n    %% ── TPS Quality Control & Offsets ───────────────────────────────────────\n    %% 3-tab dialog: Target Offsets | Target QC (lock-check + tolerance) | Two-face Tolerance.\n    %% Tolerance field hidden when LockCheckStatus checkbox OFF.\n    %% F1/CONT: UpdateData + SaveChanges + Close.\n    state TpsQualityControl {\n        [*] --> TQC_LockCheckEnabled\n        TQC_LockCheckEnabled  : LockCheckEnabled\\n(Tolerance field visible)\n        TQC_LockCheckDisabled : LockCheckDisabled\\n(Tolerance field hidden)\n\n        TQC_LockCheckEnabled  --> TQC_LockCheckDisabled : LOCK_CHECK_STATUS_CHANGED(false)\n        TQC_LockCheckDisabled --> TQC_LockCheckEnabled  : LOCK_CHECK_STATUS_CHANGED(true)\n    }\n    TpsQualityControl --> PointStorageMenu : SETTINGS_CLOSED / BACK\n\n    %% ── Imaging Quality Control ─────────────────────────────────────────────\n    %% CheckQualityBeforeStoring toggle → CheckTargets + CheckTolerance visibility.\n    %% F1 key shows OK (K_OK_TOK). OnOkPressed: StoreConfigData + Close.\n    state ImagingQualityControl {\n        [*] --> IQC_CheckQualityOff\n        IQC_CheckQualityOff : CheckQualityOff\\n(CheckTargets + CheckTolerance hidden)\n        IQC_CheckQualityOn  : CheckQualityOn\\n(CheckTargets visible;\\nCheckTolerance shown if target≠None)\n\n        IQC_CheckQualityOff --> IQC_CheckQualityOn  : CHECK_QUALITY_BEFORE_STORING_CHANGED(true)\n        IQC_CheckQualityOn  --> IQC_CheckQualityOff : CHECK_QUALITY_BEFORE_STORING_CHANGED(false)\n    }\n    ImagingQualityControl --> PointStorageMenu : SETTINGS_CLOSED / BACK\n\n    %% ── Autopole Offsets & Checks ───────────────────────────────────────────\n    %% 2-tab dialog: Pole Height Offset | Quality Check.\n    %% F1/CONT: UpdateData on both dialogs + SaveChanges + Close.\n    state AutopoleOffsetsChecks {\n        [*] --> AP_PoleHeightOffsetTab\n        AP_PoleHeightOffsetTab : PoleHeightOffsetTab\\n(length offset + persistency mode)\n        AP_QualityCheckTab     : QualityCheckTab\\n(check enable + dimension +\\nposition/height tolerance)\n\n        AP_PoleHeightOffsetTab --> AP_QualityCheckTab     : tab changed\n        AP_QualityCheckTab     --> AP_PoleHeightOffsetTab : tab changed\n    }\n    AutopoleOffsetsChecks --> PointStorageMenu : SETTINGS_CLOSED / BACK"
