    "label": "tools-clm — CLM / License Manager",
    "chart": "stateDiagram-v2\n    [*] --> checkingInstallation\n\n    checkingInstallation --> ClmMenu : clmIsInstalled\\n[WIN32 CLM.exe found, or Linux]\n    checkingInstallation --> ClmNotDetectedError : !clmIsInstalled\\n[WIN32 only — CLM.exe missing]\n\n    ClmNotDetectedError --> ClmMenu : OPERATION_DONE\\n[operator acks M_CLM_NOT_DETECTED_TOK]\n\n    state ClmMenu {\n        [*] --> idle\n        idle --> UpdateEntitlements   : SELECT_ITEM(updateEntitlements)\\n[canRefreshLicenses]\n        idle --> AddEntitlement       : SELECT_ITEM(addEntitlement)\\n[canAddEntitlement && WIN32]\n        idle --> RemoveEntitlement    : SELECT_ITEM(removeEntitlement)\\n[canRemoveEntitlement && WIN32]\n        idle --> StartTrialLicense    : SELECT_ITEM(startTrial)\\n[linux]\n        idle --> OfflineLicenseUpdate : SELECT_ITEM(offlineLicenseUpdate)\\n[linux]\n    }\n\n    state UpdateEntitlements {\n        [*] --> ue_checkingInternet\n        ue_checkingInternet --> ue_noInternet         : !internet\n        ue_checkingInternet --> ue_fetchingEntitlements : internet OK\n        ue_fetchingEntitlements --> ue_fetchFailed        : RC_NOTOK\n        ue_fetchingEntitlements --> ue_emptyEntitlements  : map empty\n        ue_fetchingEntitlements --> ue_updatingEntitlements : map populated\n        ue_emptyEntitlements --> AddEntitlement           : MBR_Yes (launch add)\n    }\n\n    state AddEntitlement {\n        [*] --> ae_checkingInternet\n        ae_checkingInternet --> ae_noInternet      : !internet\n        ae_checkingInternet --> ae_detectingAISFiles : internet OK\n        ae_detectingAISFiles --> ae_AISKeyFileView  : .key files found\n        ae_detectingAISFiles --> ae_ManualEntryView : no .key files\n        ae_AISKeyFileView --> ae_ManualEntryView    : F5 (switch to manual)\n        ae_AISKeyFileView --> ae_activating         : F1 Activate\n        ae_ManualEntryView --> ae_activating        : F1 Activate (valid input)\n        ae_activating --> done                      : full success → HandleHome\n        ae_activating --> ClmMenu                   : partial failure → close\n    }\n\n    state RemoveEntitlement {\n        [*] --> re_entitlementTree\n        re_entitlementTree --> re_rehostConfirm      : F5 Rehost (selection made)\n        re_rehostConfirm --> re_rehostingEntitlements : MBR_Yes\n        re_rehostConfirm --> re_entitlementTree       : MBR_No or !internet\n        re_rehostingEntitlements --> re_entitlementTree : result ack'd (tree rebuilt)\n    }\n\n    state StartTrialLicense {\n        [*] --> st_checkingInternet\n        st_checkingInternet --> st_noInternet            : !internet\n        st_checkingInternet --> st_checkingActivation    : internet OK\n        st_checkingActivation --> st_alreadyActivated    : already active\n        st_checkingActivation --> st_activationConfirm   : not active\n        st_activationConfirm --> st_activatingTrial      : MBR_Yes\n        st_activationConfirm --> ClmMenu                 : MBR_No\n        st_activatingTrial --> ClmMenu                   : success/fail msg ack'd\n    }\n\n    state OfflineLicenseUpdate {\n        [*] --> ol_stepSelection\n        ol_stepSelection --> ol_executingStep  : F1 OK\n        ol_executingStep --> done              : success msg OK → HandleHome\n        ol_executingStep --> ol_stepSelection  : USB missing or resp invalid\n    }\n\n    UpdateEntitlements   --> ClmMenu : OPERATION_DONE\n    RemoveEntitlement    --> ClmMenu : OPERATION_DONE\n    StartTrialLicense    --> ClmMenu : OPERATION_DONE\n    OfflineLicenseUpdate --> ClmMenu : OPERATION_DONE\n\n    ClmMenu              --> done : BACK\n    UpdateEntitlements   --> done : BACK\n    AddEntitlement       --> done : BACK\n    RemoveEntitlement    --> done : BACK\n    StartTrialLicense    --> done : BACK\n    OfflineLicenseUpdate --> done : BACK\n\n    done --> [*] : LEICA_KEY (any state)"
