    "chart": "stateDiagram-v2\n    [*] --> checkGate\n\n    checkGate --> PrismSearchSettings : canOpen\\n[DC_HasATR && SW_FEAT_SEARCHWINDOWS_CONFIG]\\n/ loadConfigData, restoreLastUsedTab\n    checkGate --> closed : else\n\n    state PrismSearchSettings {\n        direction TB\n        note right of PrismSearchSettings : F1=CONT validates all tab data then saves\\nTAB_SELECT switches active tab\\nCLOSE persists last page index\n\n        state targetPredictionTab {\n            [*] --> tp_idle\n            note right of tp_idle : Controls: PredictFor (1/3/5 s)\\nSearchWith (NoSearch/ATR/PS/LastPoint/StopSearch)\\nUseGsPosition checkbox (SK_PS or SK_ATR only)\\nSHFK5 scoped to this tab (FK registered by ConfigPrismSearchDlgC)\n            tp_idle --> tp_idle : SHFK5 / restoreTargetPredictionDefaults\\n(3 s; SK_PS if DC_HasPS else SK_ATR)\n        }\n\n        state psWindowTab {\n            [*] --> ps_idle\n            note right of ps_idle : PS_WINDOW_TOGGLE: shows/hides corner angles\\nrange-limit checkbox and DistMin/DistMax combos\\nFK2/FK4/FK5 visible only when psWindowEnabled\n            ps_idle --> ps_idle : PS_WINDOW_TOGGLE / setPsWindowEnabled\n            ps_idle --> ps_idle : RANGE_LIMIT_TOGGLE / setRangeLimitEnabled\n            ps_idle --> definingCornerLeft  : F2 [sensorConnected]\n            ps_idle --> ps_idle             : F2 [!sensorConnected]\\n(shows sensor-not-connected message)\n            ps_idle --> definingCenter      : F4 [sensorConnected]\n            ps_idle --> ps_idle             : F4 [!sensorConnected]\\n(shows sensor-not-connected message)\n            ps_idle --> positioningTelescopeLeft : F5 [sensorConnected && psWindowHasCorners]\n            ps_idle --> ps_idle             : F5 [!sensorConnected || !psWindowHasCorners]\\n(no-op or shows message)\n\n            definingCornerLeft --> definingCornerRight : MEAS_DATA_RECEIVED / recordLeftCorner\n            definingCornerLeft --> ps_idle             : MSG_CANCEL / abortWorkingAreaDef\n\n            definingCornerRight --> ps_idle : MEAS_DATA_RECEIVED / computeWorkingArea\\n(SetWorkingAreaMode=true)\n            definingCornerRight --> ps_idle : MSG_CANCEL / abortWorkingAreaDef\n\n            definingCenter --> ps_idle : MEAS_DATA_RECEIVED / recordCenter\\n(clamp V range if zenith/PI overflow;\\nSetWorkingAreaMode=true)\n\n            positioningTelescopeLeft  --> positioningTelescopeRight : MSG_OK / advancePosToRight\\n(sets PositTelescopeController direction to HzRight/V_Lower)\n            positioningTelescopeLeft  --> ps_idle                   : MSG_CANCEL / completePosRight\\n(resets POS_NULL)\n\n            positioningTelescopeRight --> ps_idle : MSG_OK / completePosRight\n            positioningTelescopeRight --> ps_idle : MSG_CANCEL / completePosRight\n        }\n\n        state atrWindowTab {\n            [*] --> atr_idle\n            note right of atr_idle : Controls: AimingMethod combo\\nHzSearch (0–399 gon; 0–195 gon on TS30/TM30 via CS)\\nVSearch (0–150 gon)\\nInfo line L_DEF_SIZE_ATR_WIN_TOK\n            atr_idle --> atr_idle : AIMING_METHOD_CHANGED / setAimingMethod\\n(AUTO_AIMING: hides Hz/V inputs, zeroes values\\nENTER_MANUALLY: shows Hz/V inputs, restores values)\n            atr_idle --> atr_idle : SHFK5 / restoreAtrDefaults\\n(ENTER_MANUALLY + 4 gon Hz + 4 gon V)\n        }\n    }\n\n    PrismSearchSettings --> PrismSearchSettings : F1 [distLimitsInvalid]\\n/ updateAllTabData, validateDistLimits, showDistValidationError\\n(shows MSG_NR_MAX_DIST_NOT_BIGGER_MIN_DIST; stays open)\n    PrismSearchSettings --> closed : F1 [!distLimitsInvalid]\\n/ updateAllTabData, validateDistLimits, saveChanges, persistLastUsedPage\n    PrismSearchSettings --> closed : CLOSE / persistLastUsedPage\n\n    closed --> [*]"
